import React from "react";
import { Outlet, Link, useLocation } from "react-router-dom";

const AdminLayout = () => {
  const location = useLocation();

  const navItems = [
    { name: "Tổng quan", path: "/admin/dashboard", icon: "📊" },
    { name: "Quản lý sản phẩm", path: "/admin/products", icon: "🛍️" },
    { name: "Quản lý đơn hàng", path: "/admin/orders", icon: "📦" },
    { name: "Quản lý danh mục", path: "/admin/categories", icon: "🗂️" },
    { name: "Quản lý người dùng", path: "/admin/users", icon: "👤" },
  ];

  const currentPage = location.pathname.replace("/admin/", "").toUpperCase();
  const isDashboard = location.pathname === "/admin/dashboard";

  return (
    <div className="flex min-h-screen font-sans bg-secondary text-[14px] leading-relaxed">
      {/* Sidebar */}
      <aside className="fixed left-0 top-0 bottom-0 w-48 bg-pink-50 border-r border-pink-100 flex flex-col shadow-sm z-50">
        {/* Logo / Profile */}
        <Link
          to="/"
          className="flex items-center gap-2 p-3 border-b border-pink-100 hover:bg-pink-100 transition"
        >
          <div className="w-8 h-8 rounded-full bg-pink-500 flex items-center justify-center text-white font-bold">
            A
          </div>
          <div className="leading-tight">
            <p className="text-sm font-semibold text-gray-800">Admin</p>
            <p className="text-xs text-pink-600">DTP Flower</p>
          </div>
        </Link>

        {/* Navigation */}
        <nav className="flex flex-col gap-1 p-2 flex-1">
          {navItems.map((item) => (
            <Link
              key={item.path}
              to={item.path}
              className={`flex items-center gap-2 px-3 py-2 rounded-md text-sm transition-all duration-200 ${
                location.pathname === item.path
                  ? "bg-pink-200 text-pink-700 font-semibold"
                  : "text-gray-700 hover:bg-pink-100 hover:text-pink-700"
              }`}
            >
              <span>{item.icon}</span>
              {item.name}
            </Link>
          ))}
        </nav>

        {/* Xem trang web */}
        <div className="p-3">
          <a
            href="/"
            className="block text-center bg-pink-500 text-white py-2 rounded-md text-sm font-semibold hover:bg-pink-600 transition"
          >
            🌸 Xem trang web
          </a>
        </div>
      </aside>

      {/* Main content */}
      <main
        className={`flex-1 ml-48 p-6 overflow-y-auto transition-colors duration-300 ${
          isDashboard ? "bg-pink-50" : "bg-secondary"
        }`}
      >
        <div className="flex justify-between items-center mb-4">
          <h1
            className={`text-base font-semibold ${
              isDashboard ? "text-pink-600" : "text-gray-800"
            }`}
          >
            {currentPage || "DASHBOARD"}
          </h1>
        </div>

        <div
          className={`p-5 rounded-lg shadow-sm min-h-[70vh] ${
            isDashboard ? "bg-white/90" : "bg-white"
          }`}
        >
          <Outlet />
        </div>
      </main>
    </div>
  );
};

export default AdminLayout;
